// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const db = new Database("data.db");

app.use(express.json());

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkBody = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderBody = {
  name?: unknown;
};

db.exec(`
  PRAGMA foreign_keys = ON;

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id),
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const hasFolderIdColumn = db
  .prepare("PRAGMA table_info(bookmarks)")
  .all()
  .some((column) => {
    return (
      typeof column === "object" &&
      column !== null &&
      "name" in column &&
      column.name === "folder_id"
    );
  });

if (!hasFolderIdColumn) {
  db.exec("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id)");
}

const bookmarkColumns =
  "id, url, title, description, folder_id, created_at, updated_at";
const folderColumns = "id, name, created_at, updated_at";

const findBookmarkById = db
  .prepare(`SELECT ${bookmarkColumns} FROM bookmarks WHERE id = ?`)
  .pluck(false);

const listBookmarks = db.prepare(
  `SELECT ${bookmarkColumns} FROM bookmarks ORDER BY id ASC`
);

const insertBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
  VALUES (@url, @title, @description, @folder_id, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      folder_id = @folder_id,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");

const findFolderById = db
  .prepare(`SELECT ${folderColumns} FROM folders WHERE id = ?`)
  .pluck(false);

const listFolders = db.prepare(`SELECT ${folderColumns} FROM folders ORDER BY id ASC`);

const listBookmarksByFolderId = db.prepare(
  `SELECT ${bookmarkColumns} FROM bookmarks WHERE folder_id = ? ORDER BY id ASC`
);

const insertFolder = db.prepare(`
  INSERT INTO folders (name, created_at, updated_at)
  VALUES (@name, @created_at, @updated_at)
`);

const updateFolder = db.prepare(`
  UPDATE folders
  SET name = @name,
      updated_at = @updated_at
  WHERE id = @id
`);

const unsetBookmarkFolder = db.prepare(
  "UPDATE bookmarks SET folder_id = NULL, updated_at = @updated_at WHERE folder_id = @folder_id"
);

const deleteFolder = db.prepare("DELETE FROM folders WHERE id = ?");

function nowIso(): string {
  return new Date().toISOString();
}

function parseBookmarkId(value: string): number | null {
  const id = Number(value);
  if (!Number.isInteger(id) || id < 1) {
    return null;
  }

  return id;
}

function getBookmark(id: number): Bookmark | undefined {
  return findBookmarkById.get(id) as Bookmark | undefined;
}

function getFolder(id: number): Folder | undefined {
  return findFolderById.get(id) as Folder | undefined;
}

function readString(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function parseOptionalFolderId(
  value: unknown
): { ok: true; value: number | null } | { ok: false; message: string } {
  if (value === undefined || value === null) {
    return { ok: true, value: null };
  }

  if (typeof value !== "number" || !Number.isInteger(value) || value < 1) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  if (!getFolder(value)) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  return { ok: true, value };
}

function validateCreateBookmark(body: BookmarkBody):
  | {
      ok: true;
      value: {
        url: string;
        title: string;
        description: string | null;
        folder_id: number | null;
      };
    }
  | { ok: false; message: string } {
  const url = readString(body.url);
  const title = readString(body.title);
  const description = readString(body.description);
  const folderId = parseOptionalFolderId(body.folder_id);

  if (!url) {
    return { ok: false, message: "url is required" };
  }

  if (!isValidUrl(url)) {
    return { ok: false, message: "url must be a valid URL" };
  }

  if (!title) {
    return { ok: false, message: "title is required" };
  }

  if (!folderId.ok) {
    return folderId;
  }

  return {
    ok: true,
    value: {
      url,
      title,
      description: description ?? null,
      folder_id: folderId.value,
    },
  };
}

function validateFolderName(body: FolderBody):
  | { ok: true; value: { name: string } }
  | { ok: false; message: string } {
  const name = readString(body.name);

  if (!name) {
    return { ok: false, message: "name is required" };
  }

  return { ok: true, value: { name } };
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/folders", (req, res) => {
  const result = validateFolderName(req.body as FolderBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const timestamp = nowIso();
  const insertResult = insertFolder.run({
    name: result.value.name,
    created_at: timestamp,
    updated_at: timestamp,
  });

  const folder = getFolder(Number(insertResult.lastInsertRowid));
  return res.status(201).json(folder);
});

app.get("/folders", (_req, res) => {
  const folders = listFolders.all() as Folder[];
  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = getFolder(id);
  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = listBookmarksByFolderId.all(id) as Bookmark[];
  return res.status(200).json({ ...folder, bookmarks });
});

app.put("/folders/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolder(id);
  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const result = validateFolderName(req.body as FolderBody);
  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  updateFolder.run({
    id,
    name: result.value.name,
    updated_at: nowIso(),
  });

  return res.status(200).json(getFolder(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolder(id);
  if (!existing) {

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const timestamp = nowIso();
  const deleteTransaction = db.transaction((folderId: number) => {
    unsetBookmarkFolder.run({ folder_id: folderId, updated_at: timestamp });
    deleteFolder.run(folderId);
  });

  deleteTransaction(id);
  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const result = validateCreateBookmark(req.body as BookmarkBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const timestamp = nowIso();
  const insertResult = insertBookmark.run({
    ...result.value,
    created_at: timestamp,
    updated_at: timestamp,
  });

  const bookmark = getBookmark(Number(insertResult.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = listBookmarks.all() as Bookmark[];
  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmark(id);
  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const existing = getBookmark(id);
  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const body = req.body as BookmarkBody;
  const url = body.url === undefined ? existing.url : readString(body.url);
  const title =
    body.title === undefined ? existing.title : readString(body.title);
  const description =
    body.description === undefined
      ? existing.description
      : readString(body.description) ?? null;
  const folderId =
    body.folder_id === undefined
      ? { ok: true as const, value: existing.folder_id }
      : parseOptionalFolderId(body.folder_id);

  if (!url) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (!title) {
    return res.status(400).json({ error: "title is required" });
  }

  if (!folderId.ok) {
    return res.status(400).json({ error: folderId.message });
  }

  updateBookmark.run({
    id,
    url,
    title,
    description,
    folder_id: folderId.value,
    updated_at: nowIso(),
  });

  return res.status(200).json(getBookmark(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = deleteBookmark.run(id);
  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

